import React from "react";

function App() {

  const checkBackend = async () => {
    const response = await fetch("http://localhost:5000");
    const data = await response.text();

    alert(data);
  };

  return (
    <div style={{
      fontFamily: "Arial",
      padding: "40px"
    }}>
      <h1>Dockerized URL Shortener</h1>

      <button
        onClick={checkBackend}
        style={{
          padding: "10px 20px",
          cursor: "pointer"
        }}
      >
        Check Backend
      </button>
    </div>
  );
}

export default App;
